dir.commands:
    &XMLWhenFilterLoading;
    &XMLWhenFilterClosing;




declare @k varchar(256)
select @k = rtrim(dvcs + ',' + ma_bp + ',' + ma_md + ',' + nh_kh1 + ',' + nh_kh2 + ',' + nh_kh3 + ',' + tien + ',' + ma_nt) from dmkieuduyet where loai_duyet = @loai_duyet and ma_kieu = @ma_kieu
select '' as field, '' as message, 'set$VoucherFilter$(this, [' + rtrim(@k) + ']);' as script
return

script.text:
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {
  sender.add_onResponseComplete(on$Filter$ResponseComplete);
  sender.setReferenceKeyFilter('ma_kieu');
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;

  switch (context) {
    case 'Checking':
      var g = f.grid, v = f._language == 'v', k = new Array();
      g._approvalType = f.getItemValue('loai_duyet');
      g._approvalCategory = f.getItemValue('ma_kieu');
      g._approvalCategoryName = f.getItemValue('ten_kieu%l');
      var type = (g._approvalType == '1');
      g._approvalName = (v ? (type ? 'Phiếu nhu cầu' : 'Đơn hàng mua') : (type ? 'Purchase Requisition' : 'Purchase Order'));
      Array.add(k, {Name: 'loai_duyet', Opr: '=', Value: g._approvalType, Type: 'String', Ignore: false});
      Array.add(k, {Name: 'ma_kieu', Opr: '=', Value: f.getItemValue('ma_kieu'), Type: 'String', Ignore: false});
      g.set_externalKey(k);
      g._alterTitle = [null, [['%c', g._approvalType + ' - ' + g._approvalName, true], ['%m', f.getItemValue('ma_kieu') + ' - ' + f.getItemValue('ten_kieu%l'), true]]];
      break;
    default:
      break;
  }
}
function onChange$Filter$ApprovalCategoryDetail$Function(o) {o.parentForm.setReferenceKeyFilter('ma_kieu');}
function set$VoucherFilter$(sender, k) {
  var g = sender.grid;
  var a = [['dvcs', 'ten_dvcs%l'], ['ma_bp', 'ten_bp%l'], ['ma_md', 'ten_md%l'], ['nh_kh1', 'ten_nh1%l'], ['nh_kh2', 'ten_nh2%l'], ['nh_kh3', 'ten_nh3%l'], ['tien'], ['ma_nt']];
  g._$u = [];
  for (var i = 0; i < a.length; i++) {Array.add(g._$u, (k[i] == '0'));}
  g._hiddenFields = [];
  for (var i = 0; i < a.length - 1; i++) {Array.add(g._hiddenFields, {Fields: a[i].join(','), Value: g._$u[i]});}
  Array.add(g._hiddenFields, {Fields: 'tien_tu, tien_den, ma_nt', Value: g._$u[6]});
  remove$GridReport$Filter(g);
}
/* </flatten> */
